const { expect } = chai;
const BASE = (process.env.OM_BASE_URL || 'http://localhost:8888').replace(/\/$/, '') + '/api/v3/openmeter';
const KEY = process.env.OM_API_KEY || '';
const HDRS = { 'Content-Type': 'application/json', ...(KEY ? { 'Authorization': `Bearer ${KEY}` } : {}) };
const sfx = `${Date.now()}_${Math.floor(Math.random() * 9999)}`;

async function api(method, path, body) {
  const resp = await fetch(`${BASE}${path}`, {
    method,
    headers: HDRS,
    ...(body !== undefined ? { body: JSON.stringify(body) } : {})
  });
  let json = null;
  try { json = await resp.json(); } catch (_) {}
  return { status: resp.status, json };
}

// Custom currency codes: 3–24 chars, must not conflict with ISO fiat codes.
// Prefix 'CUS' is not an ISO code so it is safe to use.
const code = `CUS${Date.now().toString().slice(-8)}`;

// 1. Create custom currency — symbol is required by the domain even though
// the OpenAPI schema marks it optional.
let r = await api('POST', '/currencies/custom', {
  name: `Test Token ${sfx}`,
  code,
  symbol: `T${code.slice(-3)}`
});
expect(r.status, '1. Create → 201').to.equal(201);
expect(r.json.type, '1. type').to.equal('custom');
expect(r.json.code, '1. code').to.equal(code);
expect(r.json.name, '1. name').to.equal(`Test Token ${sfx}`);
const currencyId = r.json.id;
expect(currencyId, '1. id present').to.be.ok;

// 2. List with filter[type]=custom — our currency appears, no fiat currencies.
r = await api('GET', '/currencies?filter[type]=custom&page[size]=100');
expect(r.status, '2. List custom-filtered → 200').to.equal(200);
const foundCustom = (r.json.data || []).some(c => c.id === currencyId);
expect(foundCustom, '2. custom list contains created currency').to.be.true;
const hasNoFiat = (r.json.data || []).every(c => c.type === 'custom');
expect(hasNoFiat, '2. custom filter returns only custom type').to.be.true;

// 3. List with filter[type]=fiat — no custom currencies, fiat currencies present.
r = await api('GET', '/currencies?filter[type]=fiat&page[size]=200');
expect(r.status, '3. List fiat-filtered → 200').to.equal(200);
const usd = (r.json.data || []).find(c => c.code === 'USD');
expect(usd, '3. USD in fiat list').to.be.ok;
expect(usd && usd.type, '3. USD type is fiat').to.equal('fiat');
const noCustomInFiat = (r.json.data || []).every(c => c.type === 'fiat');
expect(noCustomInFiat, '3. fiat filter returns only fiat type').to.be.true;

// 4. List unfiltered — returns both fiat and custom.
r = await api('GET', '/currencies?page[size]=200');
expect(r.status, '4. List unfiltered → 200').to.equal(200);
const foundInAll = (r.json.data || []).some(c => c.id === currencyId);
expect(foundInAll, '4. unfiltered list contains created custom currency').to.be.true;
const hasFiatInAll = (r.json.data || []).some(c => c.type === 'fiat');
expect(hasFiatInAll, '4. unfiltered list contains fiat currencies').to.be.true;

