const code = `CBT${Date.now().toString().slice(-8)}`;

// 1. Setup: create a custom currency to attach cost bases to.
let r = await api('POST', '/currencies/custom', {
  name: `Cost Basis Test ${sfx}`,
  code,
  symbol: '$'
});
expect(r.status, '1. Setup: create currency → 201').to.equal(201);
const currencyId = r.json.id;
expect(currencyId, '1. currency id present').to.be.ok;

// 2. Create cost basis for USD (rate is a decimal string; no effective_from = defaults to now).
r = await api('POST', `/currencies/custom/${currencyId}/cost-bases`, {
  fiat_code: 'USD',
  rate: '2.5'
});
expect(r.status, '2. Create cost basis (USD) → 201').to.equal(201);
expect(r.json.fiat_code, '2. fiat_code').to.equal('USD');
expect(r.json.rate, '2. rate').to.equal('2.5');
const cbUsdId = r.json.id;
expect(cbUsdId, '2. cost basis id present').to.be.ok;
expect(r.json.effective_from, '2. effective_from set').to.be.ok;

// 3. Create a second cost basis for EUR.
r = await api('POST', `/currencies/custom/${currencyId}/cost-bases`, {
  fiat_code: 'EUR',
  rate: '2.3'
});
expect(r.status, '3. Create cost basis (EUR) → 201').to.equal(201);
const cbEurId = r.json.id;

// 4. List all cost bases for this currency.
r = await api('GET', `/currencies/custom/${currencyId}/cost-bases`);
expect(r.status, '4. List cost bases → 200').to.equal(200);
const all = r.json.data || [];
expect(all.some(cb => cb.id === cbUsdId), '4. USD cost basis in list').to.be.true;
expect(all.some(cb => cb.id === cbEurId), '4. EUR cost basis in list').to.be.true;

// 5. Filter by fiat_code=USD — only USD cost basis appears.
r = await api('GET', `/currencies/custom/${currencyId}/cost-bases?filter[fiat_code]=USD`);
expect(r.status, '5. List filtered by fiat_code → 200').to.equal(200);
const usdOnly = r.json.data || [];
expect(usdOnly.some(cb => cb.id === cbUsdId), '5. USD cost basis in filtered list').to.be.true;
expect(usdOnly.every(cb => cb.fiat_code === 'USD'), '5. filtered list contains only USD').to.be.true;

// 6. Create cost basis with explicit future effective_from.
const futureDate = new Date(Date.now() + 60 * 60 * 1000).toISOString(); // 1 hour from now
r = await api('POST', `/currencies/custom/${currencyId}/cost-bases`, {
  fiat_code: 'GBP',
  rate: '1.9',
  effective_from: futureDate
});
expect(r.status, '6. Create cost basis with future effective_from → 201').to.equal(201);
expect(r.json.fiat_code, '6. fiat_code').to.equal('GBP');

