// Note: CreateCurrency handler wraps all service errors as ConflictError.
// However, because GenericValidationError is unwrapped by the error encoder,
// validation failures resolve to 400 (not 409).
// Duplicate codes use GenericConflictError from the adapter → 409.

// 1. Missing name → validation error → 400.
let r = await api('POST', '/currencies/custom', { code: 'NONAME', symbol: '!' });
expect(r.status, '1. Missing name → 400').to.equal(400);

// 2. Missing code → validation error → 400.
r = await api('POST', '/currencies/custom', { name: 'No Code Currency', symbol: '!' });
expect(r.status, '2. Missing code → 400').to.equal(400);

// 3. Missing symbol → validation error → 400 (symbol required by domain, optional in OpenAPI schema).
r = await api('POST', '/currencies/custom', { name: 'No Symbol Currency', code: 'NOSYM' });
expect(r.status, '3. Missing symbol → 400').to.equal(400);

// 4. Duplicate code: create the same code twice → second attempt → 409.
const code = `DUP${Date.now().toString().slice(-8)}`;
r = await api('POST', '/currencies/custom', { name: `Dup ${sfx}`, code, symbol: '!' });
expect(r.status, '4a. First create → 201').to.equal(201);

r = await api('POST', '/currencies/custom', { name: `Dup Again ${sfx}`, code, symbol: '!!' });
expect(r.status, '4b. Duplicate code → 409').to.equal(409);

const { expect } = chai;
const BASE = (process.env.OM_BASE_URL || 'http://localhost:8888').replace(/\/$/, '') + '/api/v3/openmeter';
const KEY = process.env.OM_API_KEY || '';
const HDRS = { 'Content-Type': 'application/json', ...(KEY ? { 'Authorization': `Bearer ${KEY}` } : {}) };
const sfx = `${Date.now()}_${Math.floor(Math.random() * 9999)}`;

async function api(method, path, body) {
  const resp = await fetch(`${BASE}${path}`, {
    method,
    headers: HDRS,
    ...(body !== undefined ? { body: JSON.stringify(body) } : {})
  });
  let json = null;
  try { json = await resp.json(); } catch (_) {}
  return { status: resp.status, json };
}

// Setup: create a real currency for cost-basis validation tests.
const code = `VAL${Date.now().toString().slice(-8)}`;
let r = await api('POST', '/currencies/custom', { name: `Validation ${sfx}`, code, symbol: '!' });
expect(r.status, 'setup: create currency → 201').to.equal(201);
const currencyId = r.json.id;

// 1. Zero rate → GenericValidationError from domain Validate() → 400.
r = await api('POST', `/currencies/custom/${currencyId}/cost-bases`, { fiat_code: 'USD', rate: '0' });
expect(r.status, '1. Zero rate → 400').to.equal(400);

// 2. Negative rate → GenericValidationError → 400.
r = await api('POST', `/currencies/custom/${currencyId}/cost-bases`, { fiat_code: 'USD', rate: '-1' });
expect(r.status, '2. Negative rate → 400').to.equal(400);

// 3. Missing fiat_code → GenericValidationError → 400.
r = await api('POST', `/currencies/custom/${currencyId}/cost-bases`, { rate: '1.0' });
expect(r.status, '3. Missing fiat_code → 400').to.equal(400);

// 4. Past effective_from → service rejects (must be in the future) → 400.
r = await api('POST', `/currencies/custom/${currencyId}/cost-bases`, {
  fiat_code: 'USD',
  rate: '1.0',
  effective_from: '2020-01-01T00:00:00Z'
});
expect(r.status, '4. Past effective_from → 400').to.equal(400);

// 5. Non-existent currency ID → FK constraint error in adapter → GenericConflictError → 409.
// Use a well-formed ULID that does not exist in the database.
r = await api('POST', '/currencies/custom/01ARZ3NDEKTSV4RRFFQ69G5FAV/cost-bases', {
  fiat_code: 'USD',
  rate: '1.0'
});
expect(r.status, '5. Non-existent currency → 409').to.equal(409);
